class DeveloperMetadata(BaseModel):
    """
    Developer metadata associated with a location or object in a spreadsheet. Developer metadata may be used to associate arbitrary data with various parts of a spreadsheet and will remain associated at those locations as they move around and the spreadsheet is edited. For example, if developer metadata is associated with row 5 and another row is then subsequently inserted above row 5, that original metadata will still be associated with the row it was first associated with (what is now row 6). If the associated object is deleted its metadata is deleted too.
    """

    model_config = ConfigDict(
        extra='forbid',
    )
    location: DeveloperMetadataLocation | None = None
    """
    The location where the metadata is associated.
    """
    metadata_id: int | None = Field(default=None, alias='metadataId')
    """
    The spreadsheet-scoped unique ID that identifies the metadata. IDs may be specified when metadata is created, otherwise one will be randomly generated and assigned. Must be positive.
    """
    metadata_key: str | None = Field(default=None, alias='metadataKey')
    """
    The metadata key. There may be multiple metadata in a spreadsheet with the same key. Developer metadata must always have a key specified.
    """
    metadata_value: str | None = Field(default=None, alias='metadataValue')
    """
    Data associated with the metadata's key.
    """
    visibility: Visibility | None = None
    """
    The metadata visibility. Developer metadata must always have a visibility specified.
    """


